#include <stdio.h>
#include <string.h>
#define MOD 1000000007

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int x[105], y[105];
        for (int i = 1; i <= m; ++i) {
            scanf("%d %d", &x[i], &y[i]);
        }
        long long dp[1005] = {0}, ndp[1005];
        long long pref[1006];
        dp[0] = 1;
        for (int i = 1; i <= m; ++i) {
            memset(ndp, 0, sizeof(ndp));
            pref[0] = 0;
            for (int s = 0; s <= n; ++s) {
                pref[s+1] = (pref[s] + dp[s]) % MOD;
            }
            for (int s = 0; s <= n; ++s) {
                int l = s - y[i];
                int r = s - x[i];
                if (r < 0) continue;               // no valid k
                if (l < 0) l = 0;
                ndp[s] = (pref[r+1] - pref[l] + MOD) % MOD;
            }
            memcpy(dp, ndp, sizeof(dp));
        }
        printf("%lld\n", dp[n] % MOD);
    }
    return 0;
}

