import java.io.*;
import java.util.*;

public class Main {
    static final long MOD = 1_000_000_007L;
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int n = fs.nextInt();
            int m = fs.nextInt();
            int[] x = new int[m+1];
            int[] y = new int[m+1];
            for (int i = 1; i <= m; i++) {
                x[i] = fs.nextInt();
                y[i] = fs.nextInt();
            }
            long[] dp = new long[n+1];
            long[] ndp = new long[n+1];
            dp[0] = 1;
            for (int i = 1; i <= m; i++) {
                Arrays.fill(ndp, 0);
                long[] pref = new long[n+2];
                for (int s = 0; s <= n; s++) pref[s+1] = (pref[s] + dp[s]) % MOD;
                for (int s = 0; s <= n; s++) {
                    int l = s - y[i];
                    int r = s - x[i];
                    if (r < 0) continue;
                    if (l < 0) l = 0;
                    ndp[s] = (pref[r+1] - pref[l] + MOD) % MOD;
                }
                long[] tmp = dp; dp = ndp; ndp = tmp;
            }
            sb.append(dp[n] % MOD).append('\n');
        }
        System.out.print(sb.toString());
    }

    // Fast scanner based on BufferedInputStream
    static class FastScanner {
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        private final InputStream in;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

