const fs = require('fs');
const MOD = 1000000007n;
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(BigInt);
let idx = 0n;
function nextInt() { return Number(input[idx++]); }
const T = nextInt();
let outputs = [];
for (let tc = 0; tc < T; ++tc) {
  const n = nextInt();
  const m = nextInt();
  const x = new Array(m+1);
  const y = new Array(m+1);
  for (let i = 1; i <= m; ++i) {
    x[i] = nextInt();
    y[i] = nextInt();
  }
  let dp = new Array(n+1).fill(0n);
  dp[0] = 1n;
  for (let i = 1; i <= m; ++i) {
    const pref = new Array(n+2).fill(0n);
    for (let s = 0; s <= n; ++s) pref[s+1] = (pref[s] + dp[s]) % MOD;
    const ndp = new Array(n+1).fill(0n);
    for (let s = 0; s <= n; ++s) {
      let l = s - y[i];
      let r = s - x[i];
      if (r < 0) continue;
      if (l < 0) l = 0;
      ndp[s] = (pref[r+1] - pref[l] + MOD) % MOD;
    }
    dp = ndp;
  }
  outputs.push(String(dp[n] % MOD));
}
